package com.google.gson.typeadapters;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonParseException;
import com.google.gson.JsonPrimitive;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.util.LinkedHashMap;
import java.util.Map;
public final class RuntimeTypeAdapterFactory<T> implements TypeAdapterFactory{
private RuntimeTypeAdapterFactory(
      Class<?> baseType, String typeFieldName, boolean maintainType) {
    if (typeFieldName == null || baseType == null) {
      throw new NullPointerException();
    }
    this.baseType = baseType;
    this.typeFieldName = typeFieldName;
    this.maintainType = maintainType;
  }
private final Class<?> baseType;
private final String typeFieldName;
private final Map<String, Class<?>> labelToSubtype = new LinkedHashMap<>();
private final Map<Class<?>, String> subtypeToLabel = new LinkedHashMap<>();
private final boolean maintainType;
private boolean recognizeSubtypes;
public static RuntimeTypeAdapterFactory<T> of(Class<T> baseType, String typeFieldName, boolean maintainType)
public static RuntimeTypeAdapterFactory<T> of(Class<T> baseType, String typeFieldName)
public static RuntimeTypeAdapterFactory<T> of(Class<T> baseType)
public RuntimeTypeAdapterFactory<T> recognizeSubtypes()
public RuntimeTypeAdapterFactory<T> registerSubtype(Class<? extends T> type, String label)
public RuntimeTypeAdapterFactory<T> registerSubtype(Class<? extends T> type)
@Override public TypeAdapter<R> create(Gson gson, TypeToken<R> type)
}
